import { useNavigate } from "react-router-dom";
import "./style.scss"
import useRequest from "../../hooks/useRequest";
import { useState } from "react";
import type { ResponseType } from "./type";

const defaultRequestData = {
    url: '/nearby.json',
    method: 'POST',
}


function Nearby() {
    const navigate=useNavigate();
    const [requestData, setRequestData] = useState(defaultRequestData)
    const { list } = useRequest<ResponseType>(requestData);

    function handleItemClick(latitude:string,longitude:string){
       localStorage.setItem('location',JSON.stringify({
        latitude,
        longitude
       }));

       navigate("home")
    }
    return (
        <div className="page nearby-page">
            <div className="title">
                <div className="iconfont title-icon" onClick={()=>{navigate("/home")}}>&#xe600;</div>切换门店
            </div>
            <div className="search">
                <span className="iconfont search-icon">&#xe60e;</span>
                <input className="search-input"
                       placeholder="请输入地址"
                />
            </div>

           
            <div className="subtitle">附近门店</div>
            <ul className="list">
                <li className="list-item" onClick={()=>{handleItemClick()}}>
                   <div className="list-item-title">优果购</div>
                   <div className="list-item-phone">联系电话:1898888888</div>
                   <div className="list-item-address">北京市昌平区南部镇四合国98号</div>
                   <div className="list-item-position">
                       <div className="iconfont list-item-position-icon">&#xe603; </div>782m
                   </div>
                </li>
            </ul>

        </div>
    )
}

export default Nearby;
